func calendarDayHeading(month, day int) string {
	if day <= 0 {
		return monthName(month) + " (unknown day)"
	}
	return fmt.Sprintf("%s %d", monthName(month), day)
}

func calendarItemTypeLabel(itemType string) string {
	switch itemType {
	case "holiday":
		return "Holiday"
	default:
		return "Event"
	}
}

func calendarItemDotClass(itemType string) string {
	switch itemType {
	case "holiday":
		return "inline-flex h-3 w-3 rounded-full border border-[#7d2a2a] bg-[#d98989]"
	default:
		return "inline-flex h-3 w-3 rounded-full border border-[#265c8a] bg-[#7cb3e2]"
	}
}

func calendarDayFormSummary(form viewmodel.CalendarItemForm) string {
	if form.EditingID > 0 {
		return "Edit Calendar Item"
	}
	return "Add Event or Holiday"
}

func calendarDayStatusClass(kind string) string {
	base := "rounded-2xl border px-4 py-3 text-sm"
	if kind == "success" {
		return base + " border-[rgba(38,101,66,0.28)] bg-[rgba(38,101,66,0.09)] text-[#1f5b3b]"
	}
	return base + " border-[rgba(111,44,38,0.28)] bg-[rgba(111,44,38,0.08)] text-[#6f2c26]"
}

